const items = $input.all();
const cfg = {};
for (const item of items) {
  cfg[item.json.Name] = item.json.Value;
}

const requiredKeys = [
  'OpenAI_ApiKey',
  'Anthropic_ApiKey',
  'prompt_canon_header',
  'prompt_qa_reviewer_a',
  'prompt_qa_reviewer_b',
  'GPT_Temperature',
  'qa_creative_instructions_shorts',
  'qa_creative_schema_shorts',
  'qa_creative_instructions_podcast',
  'qa_creative_schema_podcast'
];

for (const key of requiredKeys) {
  if (!cfg[key]) {
    throw new Error('[Build Config] Missing required key: ' + key + '. Add it to EnvironmentVariables table.');
  }
}

return [{ json: cfg }];

const shortsItems = $('n8n Table: Get Shorts Jobs').all();
const podcastItems = $('n8n Table: Get Podcast Jobs').all();

const VALID_SPEAKERS = new Set(['SAM', 'ALEX', 'JORDAN', 'RILEY']);

function normalizeSpeaker(raw) {
  const up = String(raw || '').trim().toUpperCase();
  if (VALID_SPEAKERS.has(up)) return up;
  return null;
}

function normalizeShorts(j) {
  // Priority 1: turns_json
  if (j.turns_json) {
    try {
      const turns = typeof j.turns_json === 'string'
        ? JSON.parse(j.turns_json)
        : j.turns_json;

      if (Array.isArray(turns) && turns.length > 0) {
        const lines = [];
        for (const turn of turns) {
          const speaker = normalizeSpeaker(turn && turn.speaker);
          const text = String((turn && turn.text) || '').trim();
          if (speaker && text) {
            lines.push(speaker + ': ' + text);
          }
        }
        if (lines.length > 0) {
          const distinctSpeakers = new Set(lines.map(function(l) { return l.split(':')[0]; }));
          return {
            script_text: lines.join('\n'),
            source_type: 'turns_json',
            hook_line: String(j.hook_line || ''),
            title_moment: String(j.title_moment || ''),
            turn_count: lines.length,
            shorts_format_version: 'turns_json_v1',
            shorts_dialogue_json: typeof j.turns_json === 'string' ? j.turns_json : JSON.stringify(j.turns_json),
            shorts_word_count: lines.join(' ').split(/\s+/).filter(Boolean).length,
            shorts_distinct_speakers: distinctSpeakers.size,
            shorts_reaction_detected: lines.length > 1,
            shorts_contract_warning: ''
          };
        }
      }
    } catch (e) {
      // fall through to narration_script
    }
  }

  // Priority 2: narration_script with dialogue[] (shorts_dialogue_v2 compatible)
  if (j.narration_script) {
    try {
      const ns = typeof j.narration_script === 'string'
        ? JSON.parse(j.narration_script)
        : j.narration_script;

      const dialogue = Array.isArray(ns && ns.dialogue) ? ns.dialogue : [];

      if (dialogue.length > 0) {
        const lines = dialogue.map(function(line) {
          const speaker = String((line && line.speaker) || '').trim();
          const text = String((line && line.text) || '').trim();
          return speaker && text ? (speaker + ': ' + text) : '';
        }).filter(Boolean);

        if (lines.length > 0) {
          const distinctSpeakers = new Set(lines.map(function(l) { return l.split(':')[0].trim(); }));
          const turnCount = lines.length;
          const contractWarning = distinctSpeakers.size < 2
            ? 'fewer than 2 distinct speakers'
            : (turnCount < 3 || turnCount > 6 ? 'turn count ' + turnCount + ' outside 3-6 range' : '');

          return {
            script_text: lines.join('\n'),
            source_type: 'narration_script',
            hook_line: String(j.hook_line || ''),
            title_moment: String(j.title_moment || ''),
            turn_count: turnCount,
            shorts_format_version: (ns && ns.version) || 'shorts_dialogue_v2',
            shorts_dialogue_json: JSON.stringify(dialogue),
            shorts_word_count: lines.join(' ').split(/\s+/).filter(Boolean).length,
            shorts_distinct_speakers: distinctSpeakers.size,
            shorts_reaction_detected: lines.length > 1,
            shorts_contract_warning: contractWarning
          };
        }
      }
    } catch (e) {
      // fall through to raw string
    }
  }

  // Priority 3: raw narration_script string fallback
  const raw = String(j.narration_script || '');
  if (raw.trim()) {
    return {
      script_text: raw,
      source_type: 'raw_string_fallback',
      hook_line: String(j.hook_line || ''),
      title_moment: String(j.title_moment || ''),
      turn_count: 0,
      shorts_format_version: 'legacy',
      shorts_dialogue_json: '',
      shorts_word_count: raw.split(/\s+/).filter(Boolean).length,
      shorts_distinct_speakers: 0,
      shorts_reaction_detected: false,
      shorts_contract_warning: 'raw string fallback - no structured dialogue detected'
    };
  }

  // No usable source
  return null;
}

const pending = [];

for (const item of shortsItems) {
  const j = item.json;
  if (j.script_state === 'READY' && (!j.qa_state || String(j.qa_state).trim() === '')) {
    const norm = normalizeShorts(j);

    if (!norm) {
      throw new Error('[Filter QA Pending] Shorts job ' + j.job_id + ' has no usable script source (turns_json, narration_script all empty or malformed).');
    }

    pending.push({
      json: {
        job_id: j.job_id,
        topic: j.topic,
        slug: j.slug,
        niche: j.niche,
        channel: 'shorts',
        script_text: norm.script_text,
        episode_summary: '',
        turns_json: String(j.turns_json || ''),
        beats_json: String(j.beats_json || ''),
        hook_line: norm.hook_line,
        title_moment: norm.title_moment,
        source_type: norm.source_type,
        turn_count: norm.turn_count,
        shorts_format_version: norm.shorts_format_version,
        shorts_dialogue_json: norm.shorts_dialogue_json,
        shorts_word_count: norm.shorts_word_count,
        shorts_distinct_speakers: norm.shorts_distinct_speakers,
        shorts_reaction_detected: norm.shorts_reaction_detected,
        shorts_contract_warning: norm.shorts_contract_warning
      }
    });
  }
}

for (const item of podcastItems) {
  const j = item.json;
  if (j.script_state === 'READY' && (!j.qa_state || String(j.qa_state).trim() === '')) {
    let scriptText = '';

    try {
      const arr = typeof j.script_json === 'string'
        ? JSON.parse(j.script_json)
        : j.script_json;

      const sections = {};

      for (const line of arr || []) {
        const section = String((line && line.section) || '').trim();
        const speaker = String((line && line.speaker) || '').trim();
        const text = String((line && line.text) || '').trim();

        if (!section) continue;
        if (!sections[section]) sections[section] = [];
        sections[section].push(speaker + ': ' + text);
      }

      scriptText = Object.entries(sections)
        .map(function(entry) { return '[' + entry[0] + ']\n' + entry[1].join('\n'); })
        .join('\n\n');

      if (!scriptText) {
        scriptText = String(j.script_json || '');
      }
    } catch (e) {
      scriptText = String(j.script_json || '');
    }

    pending.push({
      json: {
        job_id: j.job_id,
        topic: j.topic,
        slug: j.slug,
        niche: j.niche,
        channel: 'podcast',
        script_text: scriptText,
        episode_summary: j.episode_summary || ''
      }
    });
  }
}

if (pending.length === 0) {
  throw new Error('No QA-pending scripts found.');
}

return pending;

const cfg = $('Code: Build Config').first().json;
const items = $input.all();
const output = [];

function buildShortsStructuredContext(j) {
  const parts = [];

  if (j.hook_line) {
    parts.push('Hook line: ' + j.hook_line);
  }
  if (j.title_moment) {
    parts.push('Title moment: ' + j.title_moment);
  }
  if (j.turn_count && j.turn_count > 0) {
    parts.push('Turn count: ' + j.turn_count + ' (source: ' + (j.source_type || 'unknown') + ')');
  }
  const beatsRaw = String(j.beats_json || '').trim();
  if (beatsRaw && beatsRaw !== '""' && beatsRaw !== 'null' && beatsRaw !== '[]') {
    parts.push('beats_json present: yes');
  }

  if (parts.length === 0) return '';
  return '\n\nSHORTS STRUCTURED CONTEXT:\n' + parts.join('\n');
}

function substitute(template, vars) {
  return template.replace(/\{(\w+)\}/g, function(match, key) {
    return Object.prototype.hasOwnProperty.call(vars, key) ? vars[key] : match;
  });
}

for (const item of items) {
  const j = item.json;
  const channel = j.channel;
  const scriptText = j.script_text || '';
  const episodeSummary = j.episode_summary || '';
  const shortsContext = channel === 'shorts' ? buildShortsStructuredContext(j) : '';

  const creativeInstructions = channel === 'shorts'
    ? cfg.qa_creative_instructions_shorts
    : cfg.qa_creative_instructions_podcast;

  const creativeSchema = channel === 'shorts'
    ? cfg.qa_creative_schema_shorts
    : cfg.qa_creative_schema_podcast;

  const placeholdersA = {
    job_id: j.job_id,
    channel: channel,
    script_text: scriptText,
    episode_summary: episodeSummary,
    shorts_structured_context: shortsContext,
    canon_continuity_rules: cfg.canon_continuity_rules || ''
  };

  const placeholdersB = {
    job_id: j.job_id,
    channel: channel,
    script_text: scriptText,
    episode_summary: episodeSummary,
    shorts_structured_context: shortsContext,
    canon_bias_rules: cfg.canon_bias_rules || '',
    canon_audience: cfg.canon_audience || '',
    canon_no_go_topics: cfg.canon_no_go_topics || '',
    creative_instructions: creativeInstructions,
    creative_schema: creativeSchema
  };

  const userPromptA = substitute(cfg.prompt_qa_reviewer_a, placeholdersA);
  const userPromptB = substitute(cfg.prompt_qa_reviewer_b, placeholdersB);

  const openaiPayload = {
    model: 'gpt-5.4-mini',
    temperature: Number(cfg.GPT_Temperature),
    max_completion_tokens: 1024,
    messages: [
      { role: 'system', content: cfg.prompt_canon_header },
      { role: 'user', content: userPromptA }
    ]
  };

  const anthropicPayload = {
    model: 'claude-sonnet-4-5',
    max_tokens: 8000,
    thinking: { type: 'enabled', budget_tokens: 5000 },
    system: cfg.prompt_canon_header,
    messages: [{ role: 'user', content: userPromptB }]
  };

  output.push({
    json: {
      job_id: j.job_id,
      topic: j.topic,
      slug: j.slug,
      niche: j.niche,
      channel: channel,
      script_text: scriptText,
      episode_summary: episodeSummary,
      openai_payload: openaiPayload,
      anthropic_payload: anthropicPayload
    }
  });
}

return output;

const openaiItems = $('HTTP: QA OpenAI (Gates 1+5)').all();
const claudeItems = $('HTTP: QA Claude Sonnet (Gates 2+3+4)').all();
const promptItems = $('Code: Build QA Prompts').all();

const jobMeta = {};
for (const item of promptItems) {
  jobMeta[item.json.job_id] = {
    channel: item.json.channel,
    topic: item.json.topic,
    slug: item.json.slug
  };
}

function parseJsonObject(rawText) {
  if (!rawText) {
    throw new Error('Empty response text');
  }

  const cleaned = String(rawText).trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (!match) {
    throw new Error('No JSON object found in model response');
  }
  return JSON.parse(match[0]);
}

function getClaudeText(item) {
  const contentArr = Array.isArray(item.json.content) ? item.json.content : [];
  const text = contentArr
    .filter(function(block) { return block && block.type === 'text'; })
    .map(function(block) { return String(block.text || ''); })
    .join('\n')
    .trim();
  if (text) {
    return text;
  }
  return JSON.stringify(item.json || {});
}

function normalizeBinary(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) {
    return 0;
  }
  return num >= 1 ? 1 : 0;
}

function normalizeCreativeScore(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) {
    return null;
  }
  return Math.max(0, Math.min(10, Math.round(num)));
}

function getCreativeConfig(channel) {
  if (channel === 'shorts') {
    return {
      allFields: ['hook_strength', 'interaction_quality', 'naturalness', 'standalone_clarity', 'engagement_payoff'],
      thresholdFields: [
        { key: 'hook_strength', min: 7 },
        { key: 'interaction_quality', min: 7 },
        { key: 'standalone_clarity', min: 7 }
      ]
    };
  }

  if (channel === 'podcast') {
    return {
      allFields: ['dialogue_naturalness', 'persona_distinctness', 'escalation_quality', 'host_moderation_quality', 'section_flow'],
      thresholdFields: [
        { key: 'dialogue_naturalness', min: 7 },
        { key: 'escalation_quality', min: 7 },
        { key: 'section_flow', min: 7 }
      ]
    };
  }

  return {
    allFields: [],
    thresholdFields: []
  };
}

function buildClaudeParseFailure(rawText, reason) {
  return {
    parse_failed: true,
    parse_failed_raw: String(rawText || '').slice(0, 300),
    parse_failed_reason: reason || 'Claude response could not be parsed',
    gate_non_misleading: null,
    gate_non_misleading_note: null,
    gate_bias_free: null,
    gate_bias_free_note: null,
    gate_audience_fit: null,
    gate_audience_fit_note: null,
    creative_main_reason: null
  };
}

const openaiResults = {};
for (let i = 0; i < openaiItems.length; i++) {
  const item = openaiItems[i];
  let parsed;
  try {
    const raw = item.json && item.json.choices && item.json.choices[0] && item.json.choices[0].message
      ? item.json.choices[0].message.content
      : '';
    parsed = parseJsonObject(raw);
  } catch (error) {
    parsed = {
      gate_accuracy: 0,
      gate_accuracy_note: 'parse error - review manually',
      gate_continuity: 0,
      gate_continuity_note: 'parse error - review manually'
    };
  }

  const fallbackJobId = i < promptItems.length ? promptItems[i].json.job_id : null;
  const jobId = parsed.job_id || fallbackJobId;
  if (jobId) {
    openaiResults[jobId] = parsed;
  }
}

const claudeResults = {};
for (let i = 0; i < claudeItems.length; i++) {
  const item = claudeItems[i];
  const fallbackJobId = i < promptItems.length ? promptItems[i].json.job_id : null;
  const channel = fallbackJobId && jobMeta[fallbackJobId] ? jobMeta[fallbackJobId].channel : null;
  const creativeConfig = getCreativeConfig(channel);
  const rawText = getClaudeText(item);

  let parsed;
  try {
    parsed = parseJsonObject(rawText);
  } catch (error) {
    parsed = buildClaudeParseFailure(rawText, 'Claude response JSON could not be parsed');
  }

  if (!parsed.parse_failed) {
    for (const key of creativeConfig.allFields) {
      if (normalizeCreativeScore(parsed[key]) === null) {
        parsed = buildClaudeParseFailure(rawText, 'Creative score block missing or invalid for field ' + key);
        break;
      }
    }
  }

  const jobId = parsed.job_id || fallbackJobId;
  if (jobId) {
    claudeResults[jobId] = parsed;
  }
}

function buildEditorialFailures(data) {
  const failures = [];
  if (data.gate_accuracy !== 1) failures.push('gate_accuracy' + (data.gate_accuracy_note ? ' (' + data.gate_accuracy_note + ')' : ''));
  if (data.gate_continuity !== 1) failures.push('gate_continuity' + (data.gate_continuity_note ? ' (' + data.gate_continuity_note + ')' : ''));
  if (data.gate_non_misleading !== 1) failures.push('gate_non_misleading' + (data.gate_non_misleading_note ? ' (' + data.gate_non_misleading_note + ')' : ''));
  if (data.gate_bias_free !== 1) failures.push('gate_bias_free' + (data.gate_bias_free_note ? ' (' + data.gate_bias_free_note + ')' : ''));
  if (data.gate_audience_fit !== 1) failures.push('gate_audience_fit' + (data.gate_audience_fit_note ? ' (' + data.gate_audience_fit_note + ')' : ''));
  return failures;
}

function buildCreativeFailures(channel, creativeScores, creativeAverage) {
  const config = getCreativeConfig(channel);
  const failures = [];
  for (const threshold of config.thresholdFields) {
    const value = creativeScores[threshold.key];
    if (value === null || value < threshold.min) {
      failures.push(threshold.key + ' ' + (value === null ? 'n/a' : value + '/10') + ' < ' + threshold.min);
    }
  }
  if (!(creativeAverage >= 7.5)) {
    failures.push('creative_average ' + creativeAverage + '/10 < 7.5');
  }
  return failures;
}

function defaultCreativeScores() {
  return {
    hook_strength: null,
    interaction_quality: null,
    naturalness: null,
    standalone_clarity: null,
    engagement_payoff: null,
    dialogue_naturalness: null,
    persona_distinctness: null,
    escalation_quality: null,
    host_moderation_quality: null,
    section_flow: null
  };
}

const output = [];
const allJobIds = Array.from(new Set(Object.keys(openaiResults).concat(Object.keys(claudeResults))));

for (const jobId of allJobIds) {
  const meta = jobMeta[jobId] || {};
  const channel = meta.channel || 'unknown';
  const creativeConfig = getCreativeConfig(channel);

  const openai = openaiResults[jobId] || {
    gate_accuracy: 0,
    gate_accuracy_note: 'no openai result',
    gate_continuity: 0,
    gate_continuity_note: 'no openai result'
  };

  const claude = claudeResults[jobId] || buildClaudeParseFailure('', 'No Claude result');
  const cParseFailed = !!claude.parse_failed;

  const gate_accuracy = normalizeBinary(openai.gate_accuracy);
  const gate_continuity = normalizeBinary(openai.gate_continuity);
  const gate_non_misleading = cParseFailed ? null : normalizeBinary(claude.gate_non_misleading);
  const gate_bias_free = cParseFailed ? null : normalizeBinary(claude.gate_bias_free);
  const gate_audience_fit = cParseFailed ? null : normalizeBinary(claude.gate_audience_fit);

  const creativeScores = defaultCreativeScores();
  if (!cParseFailed) {
    for (const key of creativeConfig.allFields) {
      creativeScores[key] = normalizeCreativeScore(claude[key]);
    }
  }

  let creativeAverage = null;
  if (!cParseFailed && creativeConfig.allFields.length) {
    const sum = creativeConfig.allFields.reduce(function(total, key) {
      return total + (creativeScores[key] || 0);
    }, 0);
    creativeAverage = Number((sum / creativeConfig.allFields.length).toFixed(1));
  }

  const editorialTotalScore = gate_accuracy + gate_continuity + (gate_non_misleading || 0) + (gate_bias_free || 0) + (gate_audience_fit || 0);
  const editorialPass = !cParseFailed && editorialTotalScore === 5;
  const editorialFailures = cParseFailed ? [] : buildEditorialFailures({
    gate_accuracy: gate_accuracy,
    gate_accuracy_note: openai.gate_accuracy_note || '',
    gate_continuity: gate_continuity,
    gate_continuity_note: openai.gate_continuity_note || '',
    gate_non_misleading: gate_non_misleading,
    gate_non_misleading_note: claude.gate_non_misleading_note || '',
    gate_bias_free: gate_bias_free,
    gate_bias_free_note: claude.gate_bias_free_note || '',
    gate_audience_fit: gate_audience_fit,
    gate_audience_fit_note: claude.gate_audience_fit_note || ''
  });

  const creativeFailures = cParseFailed ? [] : buildCreativeFailures(channel, creativeScores, creativeAverage);
  const creativePass = !cParseFailed && creativeFailures.length === 0;

  let qaVerdict = 'QA_FAILED';
  if (cParseFailed) {
    qaVerdict = 'QA_PARSE_ERROR';
  } else if (editorialPass && creativePass) {
    qaVerdict = 'QA_PASSED';
  }

  let mainReason;
  if (cParseFailed) {
    mainReason = 'creative score block parse failure - ' + (claude.parse_failed_reason || 'manual review required');
  } else if (editorialFailures.length) {
    mainReason = editorialFailures[0];
  } else if (creativeFailures.length) {
    mainReason = 'creative failure, not a factual failure - ' + (String(claude.creative_main_reason || '').trim() || creativeFailures[0]);
  } else {
    mainReason = 'all editorial gates passed and creative thresholds met';
  }

  const qaNotesParts = [];
  qaNotesParts.push('Main reason: ' + mainReason);
  if (cParseFailed) {
    qaNotesParts.push('Creative parse failure: ' + (claude.parse_failed_reason || 'invalid creative score block'));
    if (claude.parse_failed_raw) {
      qaNotesParts.push('Raw response preview: ' + claude.parse_failed_raw);
    }
  } else {
    qaNotesParts.push('Editorial failures: ' + (editorialFailures.length ? editorialFailures.join('; ') : 'none'));
    qaNotesParts.push('Creative failures: ' + (creativeFailures.length ? creativeFailures.join('; ') : 'none'));
  }

  output.push({
    json: {
      job_id: jobId,
      channel: channel,
      topic: meta.topic || '',
      slug: meta.slug || '',
      qa_verdict: qaVerdict,
      qa_state: qaVerdict,
      qa_score: editorialTotalScore,
      total_score: editorialTotalScore,
      editorial_total_score: editorialTotalScore,
      creative_average: creativeAverage,
      qa_notes: qaNotesParts.join(' | '),
      gate_accuracy: gate_accuracy,
      gate_accuracy_note: openai.gate_accuracy_note || '',
      gate_continuity: gate_continuity,
      gate_continuity_note: openai.gate_continuity_note || '',
      gate_non_misleading: gate_non_misleading,
      gate_non_misleading_note: cParseFailed ? '' : (claude.gate_non_misleading_note || ''),
      gate_bias_free: gate_bias_free,
      gate_bias_free_note: cParseFailed ? '' : (claude.gate_bias_free_note || ''),
      gate_audience_fit: gate_audience_fit,
      gate_audience_fit_note: cParseFailed ? '' : (claude.gate_audience_fit_note || ''),
      hook_strength: creativeScores.hook_strength,
      interaction_quality: creativeScores.interaction_quality,
      naturalness: creativeScores.naturalness,
      standalone_clarity: creativeScores.standalone_clarity,
      engagement_payoff: creativeScores.engagement_payoff,
      dialogue_naturalness: creativeScores.dialogue_naturalness,
      persona_distinctness: creativeScores.persona_distinctness,
      escalation_quality: creativeScores.escalation_quality,
      host_moderation_quality: creativeScores.host_moderation_quality,
      section_flow: creativeScores.section_flow
    }
  });
}

return output;

const allScores = $('Code: Merge QA Scores').all();

let qa_passed = 0;
let qa_failed = 0;
let qa_parse_error = 0;
let hard_veto_count = 0;
let creative_failure_only_count = 0;
const failed_jobs = [];

for (const item of allScores) {
  const j = item.json;
  if (j.qa_verdict === 'QA_PASSED') {
    qa_passed++;
    continue;
  }

  if (j.qa_verdict === 'QA_PARSE_ERROR') {
    qa_parse_error++;
  } else {
    qa_failed++;
  }

  if (j.gate_accuracy === 0 || j.gate_bias_free === 0) {
    hard_veto_count++;
  }

  if (j.qa_verdict === 'QA_FAILED' && j.editorial_total_score === 5) {
    creative_failure_only_count++;
  }

  failed_jobs.push({
    job_id: j.job_id,
    channel: j.channel,
    qa_verdict: j.qa_verdict,
    qa_notes: j.qa_notes
  });
}

return [{
  json: {
    total_reviewed: allScores.length,
    qa_passed: qa_passed,
    qa_failed: qa_failed,
    qa_parse_error: qa_parse_error,
